var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_PERM","text":{"KOREA":"어휴, 이 계장은 어쩜 이렇게 일처리가 확실한가 몰라.","JPN":"ムラサメ係長って、ほんと仕事が早いよねえ。","ENG":"Ms. Lee is so great at her job.","TWN":"噢，李科長還真會處理事情呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_COLOR","text":{"KOREA":"그러게 말이에요. 세상에 이런 경호원이 또 어디 있어요?","JPN":"そうそう！ こんな凄腕ボディーガードはなかなかいませんよ。","ENG":"Tell me about it. You will never find a better guard than her!","TWN":"就是說呀。這世上還有哪裡能找到這麼優秀的護衛？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_OFFICE_NULL","text":{"KOREA":"하하, 하루에도 몇 번씩 지수 씨가 없었으면 어쩔 뻔했나 싶다니까요.","JPN":"ハハ！ もう、ムラサメさんのいない生活は考えられませんからね。","ENG":"I don't even want to imagine what it'd be like without her!","TWN":"哈哈，真的是一天也離不開智秀了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_OFFICE_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_NULL","text":{"KOREA":"어휴. 나 주임도 웃지만 말고 좀 보고 배워.","JPN":"イチノセ主任も笑っていないで見習ってよ～。","ENG":"Come on, now. Stop smiling and learn something from her, Mr. Na.","TWN":"哎喲，羅主任你也不要光是笑，多學學人家啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_COLOR","text":{"KOREA":"이 계장 반만이라도 따라가면 오죽 좋아.","JPN":"ムラサメ係長にちょっと教わったら？","ENG":"If only you were half as good a worker as Ms. Lee.","TWN":"要是你有李科長的一半就好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WOMAN_EXTRA_NULL_NULL","text":{"KOREA":"그런데 이 계장은 결혼 생각 없어? 내가 아주 좋은 혼삿자리를 알아 뒀는데......","JPN":"ところで、ムラサメ係長は結婚する気はないのかしら？\\n良い人紹介してあげようか？","ENG":"By the way, do you have any marriage plans, Ms. Lee? I know a most dashing young man who'd make a great husband...","TWN":"不過，李科長妳不結婚嗎？我這裡有個非常不錯的對象……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"아뇨. 괜찮지만 사양하겠습니다.","JPN":"あ、そういうのは結構です。","ENG":"No thank you. As much as I appreciate your offer, I'd rather not.","TWN":"不了，沒關係，謝謝妳的好意。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"저는 이미 일과 결혼한 몸이거든요.","JPN":"私は仕事と結婚した身ですので。","ENG":"I'm already married to my job.","TWN":"我已經和我的工作結婚了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"후, 후후...... 후후후후......","JPN":"ふ、ふふ……ふふふふ……","ENG":"Heh, heh heh... *Chuckle*","TWN":"呵，呵呵……呵呵呵呵……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"이것 봐! 또 졸고 계시네!","JPN":"また居眠りですか？","ENG":"Oh, goodness! There you go dozing off again!","TWN":"看啊！又在打瞌睡呢！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"정신 좀 차려요, 계장님!","JPN":"しっかりしてくださいよぉ、ムラサメ係長！","ENG":"Please wake up, Ms. Lee!","TWN":"醒醒啊，科長！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"핫......?!","JPN":"はっ……！？","ENG":"Huh?!","TWN":"哈……？！"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"뭐, 뭐야? 어디로 갔지? 방금까지 들려오던 무수한 칭찬 세례는......?","JPN":"えっ、何が起きた？さっきまで聞こえてた称賛の声は……？","ENG":"W-what happened? Where did they all go? They were all complimenting me just now...","TWN":"什、什麼？怎麼回事？剛剛對我的那些讚美之詞呢……？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"......뭔진 몰라도 참 딱한 꿈을 꾸셨나 보네요.","JPN":"……何だかよくわかりませんが、夢じゃないですか？","ENG":"Whatever it was you were dreaming of, I'm starting to feel real bad for you.","TWN":"……雖然不知道您夢到了什麼，但想來是個讓人遺憾的夢呢。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"무슨 일이죠? 또 과장님이 폰트 갖고 뭐라 하시던가요?","JPN":"どうしましたか？また課長にフォントのことで何か言われたりとか？","ENG":"So what now? Did the Manager say something about the font again?","TWN":"有什麼事嗎？課長又要拿字體囉嗦了嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"계장님이야말로 무슨 말씀이세요.","JPN":"係長のほうこそ、どうしたんですか？","ENG":"What are you talking about?","TWN":"科長您才是在說什麼呢？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"말도 없이 며칠 동안 감감무소식이더니, 오늘은 내내 주무시기나 하고.","JPN":"ここ数日間ずっと音信不通で、今日は居眠りしてばかり。","ENG":"You were unreachable for days, and now you're sleeping on the clock.","TWN":"一聲不響連著幾天音訊全無，今天又一直在睡覺。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"응? 이 서류들은 다 뭐예요?","JPN":"ん？　この書類は何ですか？","ENG":"Huh? What are all these documents?","TWN":"咦？這些文件是？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"설마 계장님...... 어제 밤새 일하셨어요?","JPN":"係長……まさか徹夜したんですか？","ENG":"Hang on... Have you been working all night?","TWN":"科長……難道您昨天晚上熬夜了？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"크흠. 뭐, 놀랄 것 없어요.","JPN":"まあ、驚くことはありません。","ENG":"Ahem. Nothing to be surprised about, really.","TWN":"咳咳，沒什麼好驚訝的。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"갑자기 휴가 쓰고 나갔는데 밀린 일은 끝내 둬야죠.","JPN":"急に休んでしまったので、溜まった仕事はちゃんと片付けないと。","ENG":"Catching up on the paperwork is the least I can do after taking a few days off out of the blue like that.","TWN":"我這次休假這麼突然，累積的工作當然要處理完才行。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"근무 시간에 집중해도 안 되는 걸 몰아서 하니까 이렇게 엉망진창이지......","JPN":"勤務時間に集中して対応しても終わらないような仕事を\\n駆け込みでやるから、こんなことになるんですよ……","ENG":"It's a complete mess, like always. Did you really think an overnight cram session would work, again?","TWN":"上班時間集中精神也做不完的事情偏要一起做，當然會弄得一團糟了……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"......죄, 죄송합니다.","JPN":"……す、すみません。","ENG":"S-sorry...","TWN":"……對、對不起。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"다른 분들께는 제가 말씀드릴게요. 계장님은 한숨 푹 주무시고 오세요.","JPN":"他の人には私から話しておきます。\\n係長は仮眠でも取ってきてください。","ENG":"I'll explain to the others. You go get some proper sleep.","TWN":"我會通知其他人的，科長您好好睡一覺再來吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"OFFICER_EXTRA_NULL_NULL","text":{"KOREA":"낙하산인지 뭔지 몰라도, 일만 망치면 됐지 몸까지 상하면 안 되잖아요.","JPN":"コネなのかどうかわかりませんが、\\nともあれ、健康が一番ですよ。","ENG":"I don't know if you really have connections with higher-ups, but one thing's for sure. It's okay to ruin your work, but it's not okay to ruin your health.","TWN":"不管您是不是空降還是什麼的，搞砸工作也就算了，總不能連身體都搞砸吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OFFICER_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEEJISOO_SIX_OFFICE_NULL","text":{"KOREA":"불태우는 건...... 역시 좀 미루는 게 낫겠어.","JPN":"ちょっと一息ついてから……頑張ろう。","ENG":"I suppose... I can put off burning down this place.","TWN":"放火的事……還是再延後一下吧。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_OFFICE_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};